/// <summary>
///
/// </summary>
public void dialog()
{
    Dialog                       dialog;
    RefRecId                     recId;
    DialogField                  dialogArAPRef;
    ;

    dialog = new dialog("Integration Cleanup Orphans Records");
    dialogArAPRef = dialog.addField(extendedTypeStr(RefRecId), "RecId");
    dialog.run();

    if(!dialogArAPRef.value())
    {
        throw error("RecId should be fill");
    }
    else if (dialog.run())
    {
        this.create(dialogArAPRef.value());
    }

}

/// <summary>
///
/// </summary>
/// <param name = "_fromdate"></param>
/// <param name = "_todate"></param>
public void create(int64 recId)
{
    ETG_ARAP_MSGHEADER headerMsg, _headerMsg;
    ETG_ARAP_MSGLINES  MsgLines, _MsgLines;

    int64 _recId = recId;

    select * from headerMsg where headerMsg.RecId == _recId;
    if(headerMsg)
    {
        delete_from _headerMsg
            where _headerMsg.RecId == headerMsg.RecId;

        delete_from _MsgLines
            where _MsgLines.D365HeaderRecId == headerMsg.RecId;

        info(strFmt("Duplicate Records has been deleted."));
    }
    else
    {
        info(strFmt("There is no duplicated Records."));
    }

}

/// <summary>
///
/// </summary>
/// <param name = "_args"></param>
public static void main(Args _args)
{
    ETGIntegrationCleanupOrphansRecords integrationCleanupOrphansRecords;

    integrationCleanupOrphansRecords = new ETGIntegrationCleanupOrphansRecords();
    integrationCleanupOrphansRecords.run();
}
